export default async function (_, _nuxt) {
  const { addPluginTemplate } = await import('@nuxt/kit')

  const nuxt = (this && this.nuxt) || _nuxt

  nuxt.options.css.push('floating-vue/dist/style.css')

  addPluginTemplate({
    filename: 'floating-vue.mjs',
    getContents: () => `
      import { defineNuxtPlugin } from '#imports'
      import FloatingVue from 'floating-vue'

      export default defineNuxtPlugin((nuxtApp) => {
        // @TODO cutomization
        nuxtApp.vueApp.use(FloatingVue)
      })
    `,
  })

  // @TODO remove when floating-ui supports native ESM
  nuxt.options.build.transpile.push('floating-vue', '@floating-ui/core', '@floating-ui/dom')

  // SSR support for v-tooltip directive
  nuxt.options.vue.compilerOptions.directiveTransforms = nuxt.options.vue.compilerOptions.directiveTransforms || {}
  nuxt.options.vue.compilerOptions.directiveTransforms.tooltip = () => ({
    props: [],
    needRuntime: true,
  })
}

import { nav } from '~/content'

const navLookup = nav.reduce(
  (obj, section) => ({ ...obj, [section.base.replace('/', '')]: section }),
  {}
)

// @vue/component
export default {
  name: 'BVBreadcrumbs',
  computed: {
    items() {
      const items = [{ text: 'Home', to: '/' }, { text: 'Docs', to: '/docs' }]

      const section = this.$route.name.split('-')[1] || ''
      if (section) {
        const sectionMeta = navLookup[section] || {}

        items.push({
          text: sectionMeta.title || section,
          to: ['/docs', section].join('/')
        })

        const slug = this.$route.params.slug || ''
        if (slug) {
          const pagesMeta = sectionMeta.pages || {}

          items.push({
            text: (pagesMeta[slug] || {}).title || slug,
            to: ['/docs', section, slug].join('/')
          })
        }
      }

      return items
    }
  },
  render(h) {
    return h('nav', { attrs: { 'aria-label': 'Breadcrumbs' } }, [
      h('b-breadcrumb', {
        staticClass: 'd-inline-flex my-0 px-2 py-1 bg-transparent',
        props: { items: this.items }
      })
    ])
  }
}

import { extend, mergeData } from '../../vue'
import { NAME_BUTTON_GROUP } from '../../constants/components'
import { PROP_TYPE_BOOLEAN, PROP_TYPE_STRING } from '../../constants/props'
import { pick, sortKeys } from '../../utils/object'
import { makeProp, makePropsConfigurable } from '../../utils/props'
import { props as buttonProps } from '../button/button'

// --- Props ---

export const props = makePropsConfigurable(
  sortKeys({
    ...pick(buttonProps, ['size']),
    ariaRole: makeProp(PROP_TYPE_STRING, 'group'),
    size: makeProp(PROP_TYPE_STRING),
    tag: makeProp(PROP_TYPE_STRING, 'div'),
    vertical: makeProp(PROP_TYPE_BOOLEAN, false)
  }),
  NAME_BUTTON_GROUP
)

// --- Main component ---

// @vue/component
export const BButtonGroup = /*#__PURE__*/ extend({
  name: NAME_BUTTON_GROUP,
  functional: true,
  props,
  render(h, { props, data, children }) {
    return h(
      props.tag,
      mergeData(data, {
        class: {
          'btn-group': !props.vertical,
          'btn-group-vertical': props.vertical,
          [`btn-group-${props.size}`]: props.size
        },
        attrs: { role: props.ariaRole }
      }),
      children
    )
  }
})

