// @vue/component
export const BSkeletonIcon = /*#__PURE__*/ extend({
  name: NAME_SKELETON_ICON,
  functional: true,
  props,
  render(h, { data, props }) {
    const { icon, animation } = props

    const $icon = h(BIcon, {
      staticClass: 'b-skeleton-icon',
